#!/usr/bin/env python3
# apply_tewwg_all.py  ***RUN THIS ONE, then build.py***
# Consolidated: ALL 14 assets for the Their Eyes (tewwg) deck at their FINAL values.
#   a918 deck box, a919 background, a920-a931 = 12 character portraits
#   (a925-a930 cleaner crops, a931 = full-face Rabid Dog).
# Replaces the need to run apply_tewwg.py / apply_tewwg_recrop.py / apply_rabid_dog.py.
# Usage from the repo root:  python3 apply_tewwg_all.py  &&  python3 build.py
import json, os, sys
root=os.path.dirname(os.path.abspath(__file__)); AJ=os.path.join(root,"assets","assets.json")
NEW={
  "a918": "",
  "a919": "",
  "a920": "",
  "a921": "",
  "a922": "",
  "a923": "",
  "a924": "",
  "a925": "",
  "a926": "",
  "a927": "",
  "a928": "",
  "a929": "",
  "a930": "",
  "a931": "",
}

if not os.path.exists(AJ): sys.exit("[apply] assets/assets.json not found - run from the repo root (the folder that contains the assets/ folder).")
a=json.load(open(AJ))
def raw_only(v):
    i=v.find('base64,'); return v[i+7:] if i!=-1 else v
ch=[]
for k,v in NEW.items():
    nv=raw_only(v)
    if a.get(k)!=nv: a[k]=nv; ch.append(k)
json.dump(a,open(AJ,"w"))
print(f"[apply] tewwg -> wrote {len(ch)} assets: {sorted(ch,key=lambda x:int(x[1:]))}")
print("[apply] done. Next: python3 build.py")
